+    const config = getOptInFeatureConfig(featureId);
+    const policy: OptInFeaturePolicy = config?.policy ?? "permissive";

     const { enabled: effectiveEnabled, reason: effectiveReason } = computeEffectiveStateAcrossTeams({
       globalEnabled,
"
  },
  {
    "file": "packages/features/feature-opt-in/services/FeatureOptInService.ts",
    "line": 205,
    "severity": "critical",
    "description": "Filter logic is inverted in listFeaturesForUser. The function docstring (line 187) states it returns features that are 'globally enabled', but the code filters for !state.globalEnabled (NOT globally enabled). This contradicts the parallel listFeaturesForTeam function (line 240) which correctly filters for globalEnabled, and makes no semantic sense: users would want to see enabled features, not disabled ones.",
    "fix_patch": "--- a/packages/features/feature-opt-in/services/FeatureOptInService.ts
+++ b/packages/features/feature-opt-in/services/FeatureOptInService.ts
@@ -202,7 +202,7 @@ export class FeatureOptInService implements IFeatureOptInService {
       featureIds,
     });

-    return featureIds.map((featureId) => resolvedStates[featureId]).filter((state) => !state.globalEnabled);
+    return featureIds.map((featureId) => resolvedStates[featureId]).filter((state) => state.globalEnabled);
   }

   /**
"
  },
  {
    "file": "packages/trpc/server/routers/viewer/featureOptIn/_router.ts",
    "line": 95,
    "severity": "high",
    "description": "Missing slug validation in setUserState endpoint. The setTeamState (line 117) and setOrganizationState (line 146) mutations both validate that input.slug is an opt-in feature using isOptInFeature(), but setUserState lacks this validation. This is a compliance violation: all three mutation endpoints should follow the same pattern for consistency and to fail early with clear error messages.",
    "fix_patch": "--- a/packages/trpc/server/routers/viewer/featureOptIn/_router.ts
+++ b/packages/trpc/server/routers/viewer/featureOptIn/_router.ts
@@ -93,6 +93,12 @@ export const featureOptInRouter = router({
     })
     .mutation(async ({ ctx, input }) => {
+      if (!isOptInFeature(input.slug)) {
+        throw new TRPCError({
+          code: "BAD_REQUEST",
+          message: "Invalid slug. This feature is not opt-in configurable.",
+        });
+      }
+
       await featureOptInService.setUserFeatureState({
         userId: ctx.user.id,
         featureId: input.slug,
"
  }
]

